(function () {
    'use strict';

    // ==================== CONFIG ====================
    const CONFIG = {
        STYLE_ID: 'st-preview-modal-style',
        OVERLAY_ID: 'st-preview-overlay',
        PREVIEW_MSG_COUNT: 5,
        LIST_SEARCH_DEBOUNCE_MS: 300,
        LIST_SEARCH_SNIPPETS_PER_FILE: 3,
        LIST_SEARCH_SNIPPET_CHARS: 260,
        LIST_SEARCH_MAX_SNIPPET_FILES: 40,
        SWIPE_THRESHOLD: 10,
        SLOW_HINT_MS: 3000,
        TOUCH_GUARD_MS: 300,
        ABORT_POLL_MS: 200,
        ABORT_POLL_MAX_MS: 60000,
    };

    // ==================== STYLES ====================
    const CSS = `
    :root {
        --st-preview-bg: var(--SmartThemeBlurTintColor, #21252b);
        --st-preview-text: var(--SmartThemeBodyColor, #abb2bf);
        --st-preview-border: var(--SmartThemeBorderColor, #5c6370);
        --st-preview-header: var(--SmartThemeTopBarColor, #282c34);
        --st-preview-accent: #98c379;
    }
    body .select_chat_block { display: flex !important; flex-direction: column !important; margin-bottom: 10px !important; padding: 12px !important; background-color: rgba(0,0,0,0.2) !important; border: 1px solid var(--st-preview-border) !important; border-radius: 8px !important; }
    body .select_chat_block_filename { font-size: 1.15em !important; font-weight: bold !important; color: var(--st-preview-accent) !important; margin-right: 10px !important; }
    body .select_chat_block_mes { font-size: 0.9em !important; color: var(--st-preview-text) !important; opacity: 0.8; margin-top: 5px !important; cursor: zoom-in !important; font-style: italic !important; display: -webkit-box !important; -webkit-line-clamp: 3 !important; -webkit-box-orient: vertical !important; overflow: hidden !important; white-space: normal !important; }
    @media screen and (max-width: 768px) {
        body #select_chat_popup [name="selectChatPopupHeader"],
        body #shadow_select_chat_popup [name="selectChatPopupHeader"] { flex-wrap: wrap !important; height: auto !important; align-items: center !important; gap: 8px !important; }
        body #selectChatPopupHeaderText { flex: 1 1 auto !important; min-width: 0 !important; text-align: left !important; }
        body #newChatFromManageScreenButton,
        body #chat_import_button { flex: 0 0 auto !important; }
        body #select_chat_search { order: 20 !important; flex: 1 0 100% !important; width: 100% !important; min-width: 100% !important; max-width: 100% !important; box-sizing: border-box !important; margin: 4px 0 !important; }
        body #select_chat_cross { order: 30 !important; margin-left: auto !important; }
        body #select_chat_name_wrapper > div { flex-wrap: wrap !important; height: auto !important; }
        body #select_chat_name_wrapper input[type="search"],
        body #select_chat_name_wrapper .select_chat_search_bar { width: 100% !important; min-width: 100% !important; margin-top: 5px !important; margin-bottom: 5px !important; flex-basis: 100% !important; }
    }
    #st-preview-overlay { position: fixed; top: 0; left: 0; width: 100vw; height: 100vh; background: rgba(0, 0, 0, 0.7); z-index: 20000; display: flex; align-items: center; justify-content: center; padding: 20px; box-sizing: border-box; }
    #st-preview-modal { width: 100%; max-width: 600px; max-height: 75vh; display: flex; flex-direction: column; background: var(--st-preview-bg); color: var(--st-preview-text); border: 1px solid var(--st-preview-border); border-radius: 12px; box-shadow: 0 10px 30px rgba(0,0,0,0.8); }
    @media screen and (max-width: 768px) { #st-preview-modal { max-width: 100% !important; max-height: 60vh !important; margin: auto !important; } }
    #st-preview-header { padding: 12px 15px; border-bottom: 1px solid var(--st-preview-border); display: flex; justify-content: space-between; align-items: center; background: var(--st-preview-header); border-radius: 12px 12px 0 0; flex-shrink: 0; }
    #st-preview-title { font-weight: bold; color: var(--st-preview-accent); font-size: 1.1em; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; max-width: 60%; }
    #st-preview-actions { display: flex; gap: 10px; }
    body .select_chat_block_mes.st-list-search-results { display: block !important; -webkit-line-clamp: unset !important; -webkit-box-orient: unset !important; overflow: visible !important; white-space: normal !important; font-style: normal !important; cursor: zoom-in !important; opacity: 1 !important; }
    .st-list-search-summary { font-size: 0.82em; opacity: 0.72; margin-bottom: 6px; }
    .st-list-search-snippet { padding: 7px 9px; margin-top: 6px; border-left: 2px solid var(--st-preview-accent); background: rgba(0,0,0,0.16); border-radius: 4px; line-height: 1.45; }
    .st-list-search-name { font-size: 0.78em; opacity: 0.68; margin-bottom: 3px; }
    .st-search-hit { color: var(--st-preview-accent); font-weight: bold; background: rgba(152,195,121,0.18); border-radius: 3px; padding: 0 1px; }
    .st-list-search-loading, .st-list-search-empty { opacity: 0.7; font-size: 0.9em; }
    .st-btn { padding: 6px 12px; border-radius: 4px; cursor: pointer; border: none; font-weight: bold; font-family: inherit; font-size: 0.9em; }
    .st-btn-jump { background: var(--st-preview-accent); color: #282c34; }
    .st-btn-close { background: transparent; color: var(--st-preview-text); font-size: 1.4em; padding: 0 8px; }
    #st-preview-content { flex: 1; overflow-y: auto; padding: 15px; display: flex; flex-direction: column; gap: 15px; background: var(--st-preview-bg); border-radius: 0 0 12px 12px; }
    .st-msg-row { display: flex; flex-direction: column; max-width: 100%; }
    .st-msg-row.is-user { align-items: flex-end; }
    .st-msg-row.is-char { align-items: flex-start; }
    .st-msg-bubble { padding: 10px 14px; border-radius: 8px; max-width: 88%; line-height: 1.5; font-size: 0.95em; word-wrap: break-word; white-space: pre-wrap; }
    .st-msg-row.is-user .st-msg-bubble { background: rgba(120, 120, 120, 0.2); color: var(--st-preview-text); border-bottom-right-radius: 2px; }
    .st-msg-row.is-char .st-msg-bubble { background: rgba(0, 0, 0, 0.2); color: var(--st-preview-text); border: 1px solid var(--st-preview-border); border-bottom-left-radius: 2px; }
    .st-msg-name { font-size: 0.75em; opacity: 0.6; margin-bottom: 4px; padding: 0 4px; }
    `;

    function injectStyles(parentDoc) {
        const existing = parentDoc.getElementById(CONFIG.STYLE_ID);
        if (existing) {
            existing.textContent = CSS;
            return;
        }
        const el = parentDoc.createElement('style');
        el.id = CONFIG.STYLE_ID;
        el.textContent = CSS;
        parentDoc.head.appendChild(el);
    }

    // ==================== UTILS ====================
    function escapeHtml(s) {
        return String(s == null ? '' : s)
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;')
            .replace(/'/g, '&#39;');
    }

    function escapeRegExp(s) {
        return String(s == null ? '' : s).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    }

    function splitSearchTerms(query) {
        return String(query || '').trim().toLowerCase().split(/\s+/).filter(Boolean);
    }

    function highlightSearchTerms(text, terms) {
        const escaped = escapeHtml(text).replace(/\n/g, '<br>');
        const safeTerms = [...new Set(terms || [])]
            .filter(Boolean)
            .sort((a, b) => b.length - a.length)
            .map(term => escapeRegExp(escapeHtml(term)));
        if (!safeTerms.length) return escaped;
        return escaped.replace(new RegExp('(' + safeTerms.join('|') + ')', 'gi'), '<mark class="st-search-hit">$1</mark>');
    }
    function parseChatResponse(raw) {
        if (!raw || raw === '{}') return null;
        try {
            const parsed = JSON.parse(raw);
            const arr = Array.isArray(parsed && parsed.lines) ? parsed.lines
                : Array.isArray(parsed) ? parsed : null;
            if (arr && arr.length) return arr;
        } catch (_) { /* fall through */ }
        try {
            const lines = raw.split('\n').filter(l => l.trim()).map(l => JSON.parse(l));
            return lines.length ? lines : null;
        } catch (_) { return null; }
    }

    function extractMetadata(messages) {
        const first = messages && messages[0];
        if (first && (first.user_name || first.character_name)) return first;
        return null;
    }

    // ==================== MODAL ====================
    const Modal = {
        activeRequestId: 0,
        escHandler: null,
        previousFocus: null,

        nextRequestId() { return ++this.activeRequestId; },
        isStale(id) { return id !== this.activeRequestId; },

        close(parentDoc) {
            this.activeRequestId++;
            if (this.escHandler) {
                parentDoc.removeEventListener('keydown', this.escHandler);
                this.escHandler = null;
            }
            const overlay = parentDoc.getElementById(CONFIG.OVERLAY_ID);
            if (overlay) overlay.remove();
            if (this.previousFocus && typeof this.previousFocus.focus === 'function') {
                try { this.previousFocus.focus(); } catch (_) { }
                this.previousFocus = null;
            }
        },

        open(parentDoc, fileName, onJump) {
            this.close(parentDoc);
            this.previousFocus = parentDoc.activeElement;

            const overlay = parentDoc.createElement('div');
            overlay.id = CONFIG.OVERLAY_ID;
            overlay.innerHTML = `
                <div id="st-preview-modal" role="dialog" aria-modal="true">
                    <div id="st-preview-header">
                        <div id="st-preview-title"></div>
                        <div id="st-preview-actions">
                            <button id="st-btn-jump" class="st-btn st-btn-jump"><i class="fa-solid fa-share"></i> 跳转</button>
                            <button id="st-btn-close" class="st-btn st-btn-close" aria-label="关闭"><i class="fa-solid fa-times"></i></button>
                        </div>
                    </div>
                    <div id="st-preview-content"></div>
                </div>`;
            parentDoc.body.appendChild(overlay);

            const titleDiv = overlay.querySelector('#st-preview-title');
            const contentDiv = overlay.querySelector('#st-preview-content');
            const jumpBtn = overlay.querySelector('#st-btn-jump');
            const closeBtn = overlay.querySelector('#st-btn-close');

            titleDiv.textContent = fileName;

            const close = () => this.close(parentDoc);
            closeBtn.addEventListener('click', close);
            overlay.addEventListener('click', (e) => { if (e.target === overlay) close(); });
            jumpBtn.addEventListener('click', () => { close(); if (onJump) onJump(); });

            this.escHandler = (e) => { if (e.key === 'Escape') close(); };
            parentDoc.addEventListener('keydown', this.escHandler);

            ['touchstart', 'touchend', 'touchmove'].forEach(evt => {
                overlay.addEventListener(evt, (e) => e.stopPropagation(), { passive: true });
            });

            try { jumpBtn.focus({ preventScroll: true }); } catch (_) { }

            return { overlay, titleDiv, contentDiv, jumpBtn };
        },

        showLoading(ui) {
            ui.contentDiv.innerHTML = '<div style="text-align:center; padding:20px; opacity:0.7;"><i class="fa-solid fa-spinner fa-spin"></i> 读取中...</div>';
        },

        showSlowHint(ui) {
            if (ui.contentDiv.querySelector('#st-preview-slow-hint')) return;
            const hint = ui.contentDiv.ownerDocument.createElement('div');
            hint.id = 'st-preview-slow-hint';
            hint.style.cssText = 'text-align:center; opacity:0.5; font-size:0.85em; margin-top:8px;';
            hint.textContent = '网络较慢，正在重试…';
            ui.contentDiv.appendChild(hint);
        },

        showError(ui, baseName) {
            const safe = escapeHtml(baseName);
            ui.contentDiv.innerHTML = '<div style="padding:20px; color:#e06c75; text-align:center;">'
                + '<b>读取失败</b><br>'
                + '<small style="opacity:0.8">基准名: ' + safe + '</small><br>'
                + '<small style="opacity:0.6; margin-top:8px; display:inline-block">可直接点击聊天名称打开</small>'
                + '</div>';
        },

        getMessageText(msg) {
            return msg && (msg.mes || msg.message || msg.content || msg.text || '');
        },

        getValidMessages(messages) {
            if (!Array.isArray(messages)) return [];
            return messages.map((msg, index) => ({ msg, index })).filter(item => {
                const c = this.getMessageText(item.msg);
                return c && String(c).trim() !== '';
            });
        },

        getDisplayName(msg, metadata) {
            const isUser = msg.is_user === true || msg.is_user === 'true';
            const charName = (metadata && (metadata.character_name || metadata.ch_name)) || '角色';
            const userName = (metadata && metadata.user_name) || '用户';
            let name = msg.name || msg.sender || msg.character_name || msg.user_name;
            if (!name || name === 'Unknown') name = isUser ? userName : charName;
            return name;
        },

        renderMessageList(ui, items, metadata) {
            const html = items.map(item => {
                const msg = item.msg;
                const isUser = msg.is_user === true || msg.is_user === 'true';
                const name = this.getDisplayName(msg, metadata);
                const text = this.getMessageText(msg);
                const safeName = escapeHtml(name);
                const safeText = escapeHtml(text).replace(/\n/g, '<br>');
                return '<div class="st-msg-row ' + (isUser ? 'is-user' : 'is-char') + '">'
                    + '<div class="st-msg-name">' + safeName + '<span class="st-msg-index">#' + item.index + '</span></div>'
                    + '<div class="st-msg-bubble">' + safeText + '</div>'
                    + '</div>';
            }).join('');

            ui.contentDiv.innerHTML = html;
        },

        renderMessages(ui, messages, metadata) {
            const valid = this.getValidMessages(messages);
            if (!valid.length) return false;

            const tail = valid.slice(-CONFIG.PREVIEW_MSG_COUNT);
            this.renderMessageList(ui, tail, metadata);
            ui.contentDiv.scrollTop = ui.contentDiv.scrollHeight;
            return true;
        }
    };

    // ==================== CHAT LOADER ====================
    const ChatLoader = {
        getCurrentCharacterName(parentWindow) {
            try {
                const ctxFn = parentWindow.SillyTavern && parentWindow.SillyTavern.getContext;
                if (typeof ctxFn === 'function') {
                    const ctx = ctxFn();
                    if (ctx && ctx.characters && ctx.characterId !== undefined) {
                        const c = ctx.characters[ctx.characterId];
                        if (c && c.name) return c.name;
                    }
                }
                if (parentWindow.characters && parentWindow.this_chid !== undefined) {
                    const c = parentWindow.characters[parentWindow.this_chid];
                    if (c && c.name) return c.name;
                }
                const el = parentWindow.document.querySelector('#rm_button_selected_ch .character_name, #character_name_pole, .selected_ch .ch_name');
                if (el && el.textContent) return el.textContent.trim();
                const title = parentWindow.document.querySelector('#select_chat_popup .popup_title, #shadow_select_chat_popup h3');
                if (title && title.textContent) {
                    const m = title.textContent.match(/^(.+?)(?:\s*的)?聊天|Chats? (?:for|of) (.+)/i);
                    if (m) return (m[1] || m[2]).trim();
                }
            } catch (_) { }
            return null;
        },

        extractCharNameFromFileName(fileName, parentDoc) {
            const name = fileName.trim();
            const isBranch = name.startsWith('Branch');
            const isTimestamp = /^\d/.test(name);
            const hasNormalFormat = name.includes(' - ');

            // Case 1: 标准 "角色 - 时间戳" 格式，直接拆
            if (!isBranch && !isTimestamp && hasNormalFormat) {
                return name.split(' - ')[0];
            }

            // Case 2: 分支或时间戳起头 → 从同列表其他普通命名推断
            if (isBranch || isTimestamp) {
                const blocks = parentDoc.querySelectorAll('.select_chat_block');
                for (let i = 0; i < blocks.length; i++) {
                    let fName = blocks[i].getAttribute('file_name');
                    if (!fName) {
                        const div = blocks[i].querySelector('.select_chat_block_filename');
                        if (div) fName = div.textContent.trim();
                    }
                    if (!fName) continue;
                    const clean = fName.replace(/\.jsonl$/i, '');
                    if (!clean.startsWith('Branch') && !/^\d/.test(clean) && clean.includes(' - ')) {
                        return clean.split(' - ')[0];
                    }
                }
                return null;
            }

            // Case 3: 自定义命名（无 ' - ' 也非 Branch/时间戳）→ 整名当目录候选
            return name.replace(/\.jsonl$/i, '');
        },

        generateFolderCandidates(baseName) {
            const b = String(baseName || '').trim();
            if (!b) return [];
            return [...new Set([
                b,
                'default_' + b,
                b + '1',
                b + '2',
                b + '_1',
                b.replace(/ /g, '_')
            ])];
        },

        fetchOnce(parentWindow, folder, fileName, avatarUrl, isStale) {
            return new Promise(resolve => {
                let xhr;
                try {
                    xhr = parentWindow.$.ajax({
                        type: 'POST',
                        url: '/api/chats/get',
                        data: JSON.stringify({ ch_name: folder, file_name: fileName, avatar_url: avatarUrl }),
                        contentType: 'application/json',
                        dataType: 'text',
                        success: (data) => {
                            if (isStale && isStale()) return resolve(null);
                            resolve(data);
                        },
                        error: () => resolve(null)
                    });
                } catch (_) { return resolve(null); }
                if (isStale) {
                    const timer = setInterval(() => {
                        if (isStale()) {
                            clearInterval(timer);
                            try { xhr && xhr.abort && xhr.abort(); } catch (_) { }
                        }
                    }, CONFIG.ABORT_POLL_MS);
                    setTimeout(() => clearInterval(timer), CONFIG.ABORT_POLL_MAX_MS);
                }
            });
        },

        async fetchChat(parentWindow, fileName, baseName, isStale) {
            const fileNoExt = fileName.replace(/\.jsonl$/i, '');
            const variants = [fileName, fileNoExt];

            // Stage 1: 精确路径（当前角色目录）
            for (let i = 0; i < variants.length; i++) {
                if (isStale && isStale()) return null;
                const raw = await this.fetchOnce(parentWindow, baseName, variants[i], baseName, isStale);
                const parsed = parseChatResponse(raw);
                if (parsed) return parsed;
            }

            // Stage 2: 候选目录并行兜底
            const candidates = this.generateFolderCandidates(baseName).filter(c => c !== baseName);
            if (!candidates.length) return null;

            const tasks = [];
            for (let i = 0; i < candidates.length; i++) {
                const folder = candidates[i];
                tasks.push(this.fetchOnce(parentWindow, folder, fileNoExt, '', isStale));
                tasks.push(this.fetchOnce(parentWindow, folder, fileNoExt, folder, isStale));
            }
            const results = await Promise.all(tasks);
            if (isStale && isStale()) return null;
            for (let i = 0; i < results.length; i++) {
                const parsed = parseChatResponse(results[i]);
                if (parsed) return parsed;
            }
            return null;
        }
    };

    // ==================== ORCHESTRATION ====================
    async function fetchAndShowPreview(fileName, blockElement) {
        const parentDoc = window.parent.document;
        const parentWindow = window.parent;

        // 必须先 open（其内部会 close 旧弹窗并 bump activeRequestId），再分配 myId，
        // 否则 myId 会被 open→close 链立刻作废，导致所有响应被判 stale，loading 永不结束。
        const ui = Modal.open(parentDoc, fileName, () => blockElement.click());
        const myId = Modal.nextRequestId();
        const isStale = () => Modal.isStale(myId);

        Modal.showLoading(ui);

        const slowTimer = setTimeout(() => { if (!isStale()) Modal.showSlowHint(ui); }, CONFIG.SLOW_HINT_MS);

        try {
            const baseName = ChatLoader.getCurrentCharacterName(parentWindow)
                || ChatLoader.extractCharNameFromFileName(fileName, parentDoc)
                || fileName.split(' - ')[0]
                || fileName.replace(/\.jsonl$/i, '');

            const data = await ChatLoader.fetchChat(parentWindow, fileName, baseName, isStale);
            clearTimeout(slowTimer);
            if (isStale()) return;

            if (data) {
                const metadata = extractMetadata(data);
                Modal.renderMessages(ui, data, metadata);
            } else {
                Modal.showError(ui, baseName);
            }
        } catch (_) {
            clearTimeout(slowTimer);
            if (!isStale()) Modal.showError(ui, fileName);
        }
    }

    // ==================== LIST SEARCH ====================
    const ListSearch = {
        observer: null,
        applyTimer: null,
        requestId: 0,
        activeQuery: '',
        activeResults: null,

        getHeaders(parentWindow) {
            try {
                if (typeof parentWindow.getRequestHeaders === 'function') return parentWindow.getRequestHeaders();
            } catch (_) { }
            return { 'Content-Type': 'application/json' };
        },

        getCurrentAvatarUrl(parentWindow) {
            try {
                const ctxFn = parentWindow.SillyTavern && parentWindow.SillyTavern.getContext;
                if (typeof ctxFn === 'function') {
                    const ctx = ctxFn();
                    const c = ctx && ctx.characters && ctx.characterId !== undefined ? ctx.characters[ctx.characterId] : null;
                    if (c && c.avatar) return c.avatar;
                }
                if (parentWindow.characters && parentWindow.this_chid !== undefined) {
                    const c = parentWindow.characters[parentWindow.this_chid];
                    if (c && c.avatar) return c.avatar;
                }
            } catch (_) { }
            return '';
        },

        getSelectedGroupId(parentWindow) {
            try {
                if (parentWindow.selected_group) return parentWindow.selected_group;
                const ctxFn = parentWindow.SillyTavern && parentWindow.SillyTavern.getContext;
                if (typeof ctxFn === 'function') {
                    const ctx = ctxFn();
                    return (ctx && (ctx.groupId || ctx.selected_group)) || null;
                }
            } catch (_) { }
            return null;
        },

        normalizeFileName(fileName) {
            return String(fileName || '').replace(/\.jsonl$/i, '');
        },

        getBlockFileName(block) {
            if (!block) return '';
            const nameEl = block.querySelector('.select_chat_block_filename');
            return block.getAttribute('file_name') || (nameEl && nameEl.textContent) || '';
        },

        getMessageText(msg) {
            return msg && (msg.mes || msg.message || msg.content || msg.text || '');
        },

        getDisplayName(msg, metadata) {
            const isUser = msg && (msg.is_user === true || msg.is_user === 'true');
            const charName = (metadata && (metadata.character_name || metadata.ch_name)) || '角色';
            const userName = (metadata && metadata.user_name) || '用户';
            let name = msg && (msg.name || msg.sender || msg.character_name || msg.user_name);
            if (!name || name === 'Unknown') name = isUser ? userName : charName;
            return name;
        },

        ensureOriginalPreview(mesEl) {
            if (!mesEl || mesEl.dataset.stOriginalMes !== undefined) return;
            mesEl.dataset.stOriginalMes = mesEl.textContent || '';
        },

        restoreList(parentDoc) {
            const wrappers = parentDoc.querySelectorAll('#select_chat_div .select_chat_block_wrapper');
            wrappers.forEach(wrapper => {
                wrapper.style.display = '';
                const mesEl = wrapper.querySelector('.select_chat_block_mes');
                if (!mesEl) return;
                mesEl.classList.remove('st-list-search-results');
                if (mesEl.dataset.stOriginalMes !== undefined) mesEl.textContent = mesEl.dataset.stOriginalMes;
            });
        },

        async searchFiles(parentWindow, query, avatarUrl, groupId) {
            const response = await parentWindow.fetch('/api/chats/search', {
                method: 'POST',
                headers: this.getHeaders(parentWindow),
                body: JSON.stringify({
                    query,
                    avatar_url: groupId ? null : avatarUrl,
                    group_id: groupId || null,
                }),
                cache: 'no-cache',
            });
            if (!response.ok) throw new Error('Search failed');
            const data = await response.json();
            return Array.isArray(data) ? data : [];
        },

        async fetchMessages(parentWindow, fileName, avatarUrl, groupId, isStale) {
            try {
                if (groupId) {
                    const response = await parentWindow.fetch('/api/chats/group/get', {
                        method: 'POST',
                        headers: this.getHeaders(parentWindow),
                        body: JSON.stringify({ id: this.normalizeFileName(fileName) }),
                        cache: 'no-cache',
                    });
                    if (!response.ok || (isStale && isStale())) return null;
                    return await response.json();
                }

                const dirName = String(avatarUrl || '').replace(/\.png$/i, '');
                const raw = await ChatLoader.fetchOnce(parentWindow, dirName, this.normalizeFileName(fileName), avatarUrl, isStale);
                return parseChatResponse(raw);
            } catch (_) { return null; }
        },

        makeSnippet(text, terms) {
            const raw = String(text || '');
            if (raw.length <= CONFIG.LIST_SEARCH_SNIPPET_CHARS) return raw;
            const lower = raw.toLowerCase();
            let hit = -1;
            for (let i = 0; i < terms.length; i++) {
                hit = lower.indexOf(terms[i]);
                if (hit >= 0) break;
            }
            if (hit < 0) hit = 0;
            const half = Math.floor(CONFIG.LIST_SEARCH_SNIPPET_CHARS / 2);
            const start = Math.max(0, hit - half);
            const end = Math.min(raw.length, start + CONFIG.LIST_SEARCH_SNIPPET_CHARS);
            return (start > 0 ? '...' : '') + raw.slice(start, end) + (end < raw.length ? '...' : '');
        },

        buildSnippets(messages, query, fileName) {
            const terms = splitSearchTerms(query);
            const metadata = extractMetadata(messages);
            const valid = Array.isArray(messages) ? messages.map((msg, index) => ({ msg, index })).filter(item => {
                const text = this.getMessageText(item.msg);
                return text && String(text).trim() !== '';
            }) : [];
            const matches = valid.filter(item => {
                const haystack = (this.getDisplayName(item.msg, metadata) + '\n' + this.getMessageText(item.msg)).toLowerCase();
                return terms.every(term => haystack.includes(term));
            });

            if (!matches.length) {
                const titleMatch = terms.length && terms.every(term => String(fileName || '').toLowerCase().includes(term));
                return { total: titleMatch ? 1 : 0, html: titleMatch ? '<div class="st-list-search-summary">文件名匹配</div>' : '<div class="st-list-search-empty">未能读取到具体命中楼层</div>' };
            }

            const snippets = matches.slice(0, CONFIG.LIST_SEARCH_SNIPPETS_PER_FILE).map(item => {
                const name = escapeHtml(this.getDisplayName(item.msg, metadata));
                const text = highlightSearchTerms(this.makeSnippet(this.getMessageText(item.msg), terms), terms);
                return '<div class="st-list-search-snippet">'
                    + '<div class="st-list-search-name">#' + item.index + ' · ' + name + '</div>'
                    + '<div>' + text + '</div>'
                    + '</div>';
            }).join('');

            return {
                total: matches.length,
                html: '<div class="st-list-search-summary">命中 ' + matches.length + ' 条消息</div>' + snippets,
            };
        },

        async renderSnippets(parentWindow, block, query, avatarUrl, groupId, requestId) {
            const mesEl = block && block.querySelector('.select_chat_block_mes');
            const fileName = this.getBlockFileName(block);
            if (!mesEl || !fileName) return;
            this.ensureOriginalPreview(mesEl);
            mesEl.classList.add('st-list-search-results');
            mesEl.innerHTML = '<span class="st-list-search-loading"><i class="fa-solid fa-spinner fa-spin"></i> 正在读取命中片段...</span>';

            const messages = await this.fetchMessages(parentWindow, fileName, avatarUrl, groupId, () => requestId !== this.requestId);
            if (requestId !== this.requestId) return;
            const result = this.buildSnippets(messages, query, fileName);
            mesEl.innerHTML = result.html;
        },

        applyResults(parentDoc, parentWindow, query, results, avatarUrl, groupId, requestId) {
            if (requestId !== this.requestId) return;
            const byName = new Map();
            results.forEach(item => {
                byName.set(this.normalizeFileName(item.file_name), item);
                byName.set(String(item.file_name || ''), item);
            });

            const wrappers = Array.from(parentDoc.querySelectorAll('#select_chat_div .select_chat_block_wrapper'));
            let rendered = 0;
            wrappers.forEach(wrapper => {
                const block = wrapper.querySelector('.select_chat_block');
                const fileName = this.getBlockFileName(block);
                const matched = byName.has(this.normalizeFileName(fileName)) || byName.has(fileName);
                wrapper.style.display = matched ? '' : 'none';
                if (!matched || !block) return;
                const mesEl = block.querySelector('.select_chat_block_mes');
                if (mesEl) this.ensureOriginalPreview(mesEl);
                if (rendered < CONFIG.LIST_SEARCH_MAX_SNIPPET_FILES) {
                    rendered++;
                    this.renderSnippets(parentWindow, block, query, avatarUrl, groupId, requestId);
                }
            });
        },

        async run(parentDoc, parentWindow, query) {
            this.activeQuery = query;
            const requestId = ++this.requestId;
            if (!query.trim()) {
                this.activeResults = null;
                this.restoreList(parentDoc);
                return;
            }

            const avatarUrl = this.getCurrentAvatarUrl(parentWindow);
            const groupId = this.getSelectedGroupId(parentWindow);
            if (!avatarUrl && !groupId) return;

            try {
                const results = await this.searchFiles(parentWindow, query, avatarUrl, groupId);
                if (requestId !== this.requestId) return;
                this.activeResults = { query, results, avatarUrl, groupId, requestId };
                setTimeout(() => this.applyResults(parentDoc, parentWindow, query, results, avatarUrl, groupId, requestId), 80);
            } catch (_) {
                // SillyTavern 自带搜索仍会工作；这里失败时只是不显示命中片段。
            }
        },

        isOwnSnippetMutation(mutations) {
            return Array.from(mutations || []).every(mutation => {
                const target = mutation.target;
                return target && target.closest && target.closest('.select_chat_block_mes.st-list-search-results');
            });
        },

        bind(parentDoc, parentWindow) {
            const $ = parentWindow.$;
            if (!$) return;
            const $input = $('#select_chat_search', parentDoc);
            if (!$input.length) return;
            let timer = null;
            $input.off('input.stPreviewListSearch').on('input.stPreviewListSearch', () => {
                clearTimeout(timer);
                const query = String($input.val() || '');
                timer = setTimeout(() => this.run(parentDoc, parentWindow, query), CONFIG.LIST_SEARCH_DEBOUNCE_MS);
            });
        },

        observe(parentDoc, parentWindow) {
            if (this.observer) this.observer.disconnect();
            const target = parentDoc.getElementById('select_chat_popup')
                || parentDoc.getElementById('shadow_select_chat_popup')
                || parentDoc.body;
            this.observer = new MutationObserver((mutations) => {
                if (this.isOwnSnippetMutation(mutations)) return;
                this.bind(parentDoc, parentWindow);
                if (this.activeResults && this.activeQuery.trim()) {
                    clearTimeout(this.applyTimer);
                    this.applyTimer = setTimeout(() => {
                        const r = this.activeResults;
                        this.applyResults(parentDoc, parentWindow, r.query, r.results, r.avatarUrl, r.groupId, r.requestId);
                    }, 120);
                }
            });
            this.observer.observe(target, { childList: true, subtree: true });
            this.bind(parentDoc, parentWindow);
        }
    };

    // ==================== LAYOUT TWEAKS ====================
    // 把删除按钮挪到铅笔按钮左侧，避免误触
    const Layout = {
        observer: null,

        rearrange(block) {
            if (!block || block.dataset.stReordered === '1') return;
            const del = block.querySelector('.PastChat_cross, [class*="trash"], .fa-trash, .fa-times');
            const rename = block.querySelector('.renameChatButton, .fa-pen, .fa-pencil');
            if (!del || !rename) return;
            // 把 del 插到 rename 之前
            if (rename.previousElementSibling !== del) {
                rename.parentNode.insertBefore(del, rename);
            }
            block.dataset.stReordered = '1';
        },

        rearrangeAll(parentDoc) {
            const blocks = parentDoc.querySelectorAll('.select_chat_block');
            blocks.forEach(b => this.rearrange(b));
        },

        observe(parentDoc) {
            if (this.observer) this.observer.disconnect();
            const popup = parentDoc.getElementById('select_chat_popup')
                || parentDoc.getElementById('shadow_select_chat_popup')
                || parentDoc.body;
            this.observer = new MutationObserver(() => this.rearrangeAll(parentDoc));
            this.observer.observe(popup, { childList: true, subtree: true });
            this.rearrangeAll(parentDoc);
        }
    };

    // ==================== EVENTS ====================
    function init() {
        const parentDoc = window.parent.document;
        const $ = window.parent.$;
        if (!$) return;

        injectStyles(parentDoc);
        $('body').off('.stPreview');
        Layout.observe(parentDoc);
        ListSearch.observe(parentDoc, window.parent);

        let touchStartPos = null;
        let touchHandled = false;

        const isOverlayOpen = () => !!parentDoc.getElementById(CONFIG.OVERLAY_ID);

        // 白名单委托：只对消息预览文本本身绑定事件，根本不触达删除/重命名/导出等按钮
        const TRIGGER_SEL = '.select_chat_block_mes';

        function getBlock($el) {
            return $el.closest('.select_chat_block');
        }

        function trigger(e, $block) {
            if (isOverlayOpen()) return false;
            const fileName = $block.attr('file_name');
            if (!fileName) return false;
            e.preventDefault();
            e.stopPropagation();
            // 阻止事件冒泡到 SillyTavern 的原生 click 处理（避免父级 .select_chat_block 触发跳转）
            if (e.stopImmediatePropagation) e.stopImmediatePropagation();
            fetchAndShowPreview(fileName, $block[0]);
            return true;
        }

        $('body').on('touchstart.stPreview', TRIGGER_SEL, function (e) {
            if (isOverlayOpen()) { touchStartPos = null; return; }
            const t = e.originalEvent.touches[0];
            touchStartPos = { x: t.clientX, y: t.clientY };
        });

        $('body').on('touchend.stPreview', TRIGGER_SEL, function (e) {
            if (!touchStartPos || isOverlayOpen()) { touchStartPos = null; return; }
            const t = e.originalEvent.changedTouches[0];
            const dx = Math.abs(t.clientX - touchStartPos.x);
            const dy = Math.abs(t.clientY - touchStartPos.y);
            touchStartPos = null;
            if (dx > CONFIG.SWIPE_THRESHOLD || dy > CONFIG.SWIPE_THRESHOLD) return;
            const $block = getBlock($(this));
            if (!$block.length) return;
            if (trigger(e, $block)) {
                touchHandled = true;
                setTimeout(() => { touchHandled = false; }, CONFIG.TOUCH_GUARD_MS);
            }
        });

        $('body').on('click.stPreview', TRIGGER_SEL, function (e) {
            if (touchHandled) { touchHandled = false; return; }
            const $block = getBlock($(this));
            if ($block.length) trigger(e, $block);
        });
    }

    init();
})();
